import xml.etree.ElementTree as ET
from xml.dom import minidom
import os
from typing import Optional, Dict, Any, List
import re


def validate_xml_file(
    file_path: str,
    max_size_mb: float = 10,
    allowed_tags: Optional[List[str]] = None,
    required_tags: Optional[List[str]] = None,
    validate_structure: bool = True
) -> Dict[str, Any]:
    
    result = {
        'valid': False,
        'errors': [],
        'warnings': [],
        'root_tag': None,
        'num_elements': 0,
        'file_size_mb': 0
    }
    
    if not os.path.exists(file_path):
        result['errors'].append(f"File not found: {file_path}")
        return result
    
    file_size = os.path.getsize(file_path)
    file_size_mb = file_size / (1024 * 1024)
    result['file_size_mb'] = round(file_size_mb, 2)
    
    if file_size_mb > max_size_mb:
        result['errors'].append(f"File size ({file_size_mb:.2f} MB) exceeds maximum allowed size ({max_size_mb} MB)")
        return result
    
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        result['root_tag'] = root.tag
        
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
        return result
    except Exception as e:
        result['errors'].append(f"Error reading file: {str(e)}")
        return result
    
    all_elements = list(root.iter())
    result['num_elements'] = len(all_elements)
    
    if validate_structure:
        found_tags = set()
        for elem in all_elements:
            tag_name = elem.tag
            if '}' in tag_name:
                tag_name = tag_name.split('}')[1]
            found_tags.add(tag_name)
        
        if allowed_tags:
            invalid_tags = found_tags - set(allowed_tags)
            if invalid_tags:
                result['warnings'].append(f"Found tags not in allowed list: {', '.join(invalid_tags)}")
        
        if required_tags:
            missing_tags = set(required_tags) - found_tags
            if missing_tags:
                result['errors'].append(f"Missing required tags: {', '.join(missing_tags)}")
                return result
    
    for elem in all_elements:
        if elem.text and elem.text.strip():
            if len(elem.text) > 1000000:
                result['warnings'].append(f"Element '{elem.tag}' has very large text content")
    
    if not result['errors']:
        result['valid'] = True
    
    return result


def validate_xml_string(
    xml_string: str,
    max_size_kb: float = 1024,
    allowed_tags: Optional[List[str]] = None,
    required_tags: Optional[List[str]] = None
) -> Dict[str, Any]:
    
    result = {
        'valid': False,
        'errors': [],
        'warnings': [],
        'root_tag': None,
        'num_elements': 0,
        'size_kb': 0
    }
    
    if not xml_string or not xml_string.strip():
        result['errors'].append("Empty XML string provided")
        return result
    
    size_kb = len(xml_string.encode('utf-8')) / 1024
    result['size_kb'] = round(size_kb, 2)
    
    if size_kb > max_size_kb:
        result['errors'].append(f"XML size ({size_kb:.2f} KB) exceeds maximum allowed size ({max_size_kb} KB)")
        return result
    
    try:
        root = ET.fromstring(xml_string)
        result['root_tag'] = root.tag
        
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
        return result
    except Exception as e:
        result['errors'].append(f"Error parsing XML: {str(e)}")
        return result
    
    all_elements = list(root.iter())
    result['num_elements'] = len(all_elements)
    
    found_tags = set()
    for elem in all_elements:
        tag_name = elem.tag
        if '}' in tag_name:
            tag_name = tag_name.split('}')[1]
        found_tags.add(tag_name)
    
    if allowed_tags:
        invalid_tags = found_tags - set(allowed_tags)
        if invalid_tags:
            result['warnings'].append(f"Found tags not in allowed list: {', '.join(invalid_tags)}")
    
    if required_tags:
        missing_tags = set(required_tags) - found_tags
        if missing_tags:
            result['errors'].append(f"Missing required tags: {', '.join(missing_tags)}")
            return result
    
    if not result['errors']:
        result['valid'] = True
    
    return result


def read_and_validate_xml(
    source: str,
    is_file: bool = True,
    max_size_mb: float = 10,
    allowed_tags: Optional[List[str]] = None,
    required_tags: Optional[List[str]] = None,
    validate_structure: bool = True,
    pretty_print: bool = False
) -> Dict[str, Any]:
    
    if is_file:
        result = validate_xml_file(
            file_path=source,
            max_size_mb=max_size_mb,
            allowed_tags=allowed_tags,
            required_tags=required_tags,
            validate_structure=validate_structure
        )
        
        if result['valid'] and pretty_print:
            try:
                tree = ET.parse(source)
                root = tree.getroot()
                xml_str = ET.tostring(root, encoding='unicode')
                dom = minidom.parseString(xml_str)
                result['pretty_xml'] = dom.toprettyxml(indent="  ")
            except Exception as e:
                result['warnings'].append(f"Could not pretty print XML: {str(e)}")
    else:
        result = validate_xml_string(
            xml_string=source,
            max_size_kb=max_size_mb * 1024,
            allowed_tags=allowed_tags,
            required_tags=required_tags
        )
        
        if result['valid'] and pretty_print:
            try:
                root = ET.fromstring(source)
                xml_str = ET.tostring(root, encoding='unicode')
                dom = minidom.parseString(xml_str)
                result['pretty_xml'] = dom.toprettyxml(indent="  ")
            except Exception as e:
                result['warnings'].append(f"Could not pretty print XML: {str(e)}")
    
    return result